"""
MKT Context Commentary — Deuteronomy chapters 3–4 (gap fill)
Run: python3 scripts/zc-context-deuteronomy-3-4-fill.py

Fills all 78 verses (ch 3: 29 verses, ch 4: 49 verses).
Existing sparse entries from prior Phase 2 script are overridden
by fuller coverage (merge_comm is skip-safe on per-verse keys).

Source data:
- data/interlinear/deuteronomy.json
- data/translation/draft/mediating/deuteronomy.json
- data/commentary/ellicott/deuteronomy.json

Key decisions:
- herem in ch 3 treated as covenantal holy war category (ANE parallel)
- Rephaim/giant traditions taken as historical ethnographic claims
- Suzerainty-treaty framework (Kline) carried forward from chs 1-2
- Pisgah vision (3:27) treated as ANE symbolic land-grant convention
- Ch 4 aniconic theology grounded in formless Horeb theophany (4:12, 4:15)
- 'Iron furnace' (4:20) as metallurgical metaphor for Egypt's oppression
- ein od (4:35, 4:39) traced toward Second Isaiah's exclusive monotheism
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DEUTERONOMY = {
  "3": {
    "1": "<p>'Then we turned and went up the road to Bashan' — the Bashan campaign immediately follows the Sihon victory (Deut 2:24-37). Og king of Bashan controlled the plateau and forest region northeast of the Sea of Galilee, modern-day Golan Heights and Hauran. Edrei (modern Der'a in southern Syria) was Og's fortified capital, strategically placed on the eastern plateau. The march 'up' reflects the ascent from the Jordan rift valley to the Bashan tablelands. Moses frames the campaign as the continuation of YHWH's program established in the Sihon victory — same divine guarantee, same military situation, same expected outcome.</p>",
    "2": "<p>'Do not fear him, for I have given him and all his people and his land into your hand. Do to him as you did to Sihon' — the divine reassurance formula applied to Og establishes the Sihon victory as juridical precedent. 'Do to him as you did to Sihon' is not merely encouragement but a binding commission: what YHWH authorized and accomplished against Sihon's Heshbon establishes the herem-template for Bashan. The repetition of the formula (cf. Deut 2:24, 31; 3:2) signals the suzerain's consistent authorization across multiple campaigns rather than ad hoc permission for each engagement.</p>",
    "3": "<p>The victory formula — 'so the LORD our God gave into our hands Og also ... and we struck him down until not one survivor remained' — mirrors the Sihon formula almost exactly (Deut 2:33). The identical language is deliberate: YHWH's pattern of warfare against Transjordanian kings follows a fixed template. In the suzerainty framework, the great king delivers the enemy; the vassal's army executes; the result is total. The phrase 'until not one survivor remained' is the <em>herem</em>-formula's outcome: the victory is understood as YHWH's claimed judgment, not merely military success.</p>",
    "4": "<p>'There was not a city we did not take from them — sixty cities, the entire region of Argob' — the Argob region (modern Leja, a large basalt plateau in Hauran) was a geographically defined administrative unit within Og's kingdom. The number sixty is verifiable: Jair's renaming of the region's towns in v. 14 reflects the administrative reality of a network of settlements. The hyperbolic flavor ('not a city we did not take') is the ANE conquest-annals idiom for comprehensive victory, attested in Egyptian and Assyrian campaign records that use the same rhetoric of total urban subjugation.</p>",
    "5": "<p>'Cities fortified with high walls, gates, and bars, besides very many unwalled villages' — the distinction between fortified cities (<em>ʿārîm bĕṣurôt</em>) and unwalled settlements (<em>ḥăṣērîm</em>) reflects the standard ANE settlement hierarchy. Fortified cities had stone walls, bronze-sheathed gates, and heavy wooden bars; their conquest required siege equipment or divine intervention. Unwalled villages were agricultural dependencies of the city-center. The enumeration demonstrates that YHWH's gift encompassed both the military fortresses and the civilian population centers that sustained them.</p>",
    "6": "<p>'We devoted them to destruction, as we had done to Sihon king of Heshbon, putting every city under the ban — men, women, and children' — <em>herem</em> (devotion to destruction) is the highest category of sacred warfare in the ANE: captured persons and possessions become irrevocably forfeit to the deity who granted victory. Hittite, Assyrian, and Moabite sources all attest similar concepts of total dedication of the defeated. The Mesha Stele (Moabite, 9th century BCE) uses the cognate term for Kemosh's commanded destruction of Israelite populations. Within Israel's theology, <em>herem</em> prevents cultic contamination from Canaanite religion entering the covenant community.</p>",
    "7": "<p>'But all the livestock and the plunder from the cities we kept for ourselves' — the distinction between persons (subject to total herem) and livestock and goods (retainable as spoil) reflects the graduated scale of ANE sacred warfare. The Deuteronomic law distinguishes between distant cities (Deut 20:14: take women, children, livestock, plunder) and Canaanite cities (Deut 20:16-17: herem all that breathes). The Transjordanian kings fall into the herem category for persons but the spoil is legitimate booty — demonstrating that herem is the dedicating of human life to YHWH's judgment, not necessarily total annihilation of all material value.</p>",
    "8": "<p>'At that time we took the land east of the Jordan from the two Amorite kings — from the Valley of the Arnon to Mount Hermon' — the Arnon to Hermon extent describes the complete Transjordanian plateau from the deep canyon that formed the Moab-Ammonite border (Arnon, modern Wadi Mujib in Jordan) to the snow-capped volcanic massif in the north (Hermon, 2,814m). This geographic bracket defines the entirety of what became Israel's Transjordanian holdings. The summary bracket frames the two campaigns (Sihon of Heshbon, Og of Bashan) as a single unified territorial acquisition.</p>",
    "9": "<p>'Hermon is called Sirion by the Sidonians and Senir by the Amorites' — a parenthetical ethnolinguistic note attesting multiple ancient names for Mount Hermon. The Sidonians (Phoenicians) called it Sirion or Shiryôn; the Amorites called it Senir or Shenir. The Ugaritic texts (14th-12th century BCE) refer to Hermon as Ṣryn, closely related to Sirion. The multiple names reflect the mountain's significance as a geographical landmark visible across a vast region and claimed by multiple cultures as their own sacred or identifying peak. The Psalmist celebrates Hermon's dew in Psalm 133:3 as an image of covenant unity.</p>",
    "10": "<p>'All the cities of the plateau, all Gilead, and all Bashan as far as Salecah and Edrei' — the geographic summary enumerates Og's kingdom in full. The plateau (<em>miśôr</em>) refers to the tablelands of Moab and northern Transjordan. Gilead is the forested hill country between the Yarmuk and Jabbok rivers. Salecah (modern Salkhad) was the easternmost city of the Bashan plateau, at the edge of the Syrian desert. The enumeration from south (the plain) through Gilead to the full extent of Bashan defines the territory distributed among Reuben, Gad, and half-Manasseh in the following verses.</p>",
    "11": "<p>Og's iron bed (9×4 cubits, approximately 4m × 2m) is noted as preserved at Rabbah of the Ammonites (modern Amman, Jordan), functioning as a display piece or royal trophy in the period of Deuteronomy's composition. The object is variously identified as: (1) a royal basalt sarcophagus (basalt is abundant in Bashan and appears black like iron), (2) an actual iron-framed bed demonstrating royal status, or (3) a cultic object. 'Rephaim' in the Transjordanian texts denotes a pre-Israelite population associated with exceptional stature (Deut 2:11, 2:20; Gen 14:5; 15:20); in later Hebrew the word shifts to mean 'shades' — the dead in Sheol (Isa 14:9; Prov 9:18) — a fusion of giant-race and underworld-ancestor traditions. The defeat of Og as 'the last of the Rephaim' (3:11) is a deliberate literary closure: Israel's entry into the promised land eliminates the last survivors of the pre-Abrahamic peoples whose terror had paralyzed Israel at Kadesh (Num 13:33: 'we seemed to ourselves like grasshoppers').</p>",
    "12": "<p>'This land that we took possession of — from Aroer by the Arnon River and half the hill country of Gilead with its cities — I gave to the Reubenites and Gadites' — the land distribution records begin with Reuben and Gad's southern portion. Aroer (modern Arair, on the north bank of the Arnon canyon) was the southernmost point of the allocation. The half of Gilead given to Reuben and Gad was the southern section below the Jabbok. This distribution reflects the original request of Reuben and Gad (Num 32) who had large livestock herds and preferred the Transjordanian pastureland to the more densely forested western territory.</p>",
    "13": "<p>'The rest of Gilead and all Bashan, the kingdom of Og, I gave to the half-tribe of Manasseh. (The whole region of Argob in Bashan was called the land of the Rephaim)' — Manasseh's half-tribe received the northern portion: northern Gilead plus all Bashan. The Argob district (the large basalt Leja plateau) is identified as formerly Rephaim territory, reinforcing the continuity between YHWH's gift to Israel and the prehistoric displacement of earlier giant-peoples. Manasseh's Transjordanian settlement later became problematic — the Gileadite/Manassite territory east of the Jordan was among the first to fall to Assyria (2 Kings 15:29).</p>",
    "14": "<p>'Jair the Manassite took all the region of Argob as far as the border of the Geshurites and the Maacathites. He named those villages Havvoth-jair — as it is still called today' — the naming of Bashan's villages after Jair reflects the ANE land-claim custom of eponymous naming: the conqueror's name applied to conquered territory signals ownership and memorializes the acquisition. Geshur and Maacah were small Aramean kingdoms at the northern boundary of Israel's Transjordanian holdings; they remained semi-independent (David later married a Geshurite princess, 2 Sam 3:3). The 'as it is still called today' note signals the author's post-conquest vantage point.</p>",
    "15": "<p>'To Machir I gave Gilead' — Machir son of Manasseh is the eponymous ancestor of the Machirites, who are associated specifically with Gilead throughout the tribal histories (Num 32:39-40; Josh 17:1). This single-sentence allocation is an abbreviated cross-reference to the more extensive account in Numbers 32. The brevity signals that Moses's audience knew the tribal geography; the reminder in this context serves the retrospective framing of Deuteronomy 1-3 rather than providing new information about territory already settled.</p>",
    "16": "<p>'To the Reubenites and Gadites I gave the territory from Gilead down to the Arnon Valley, with the middle of the valley as the boundary, as far as the Jabbok River, which is the Ammonite border' — the precise boundary description (mid-valley of the Arnon; the Jabbok as the Ammonite border) reflects the kind of boundary-treaty language attested in ANE land-grant documents. The Arnon canyon's middle line as the boundary suggests recognized natural-frontier diplomacy between Moabite territory (to the south) and Israelite territory (to the north).</p>",
    "17": "<p>'The Arabah as well, with the Jordan as the western boundary, from Chinnereth down to the Sea of the Arabah, the Salt Sea, below the slopes of Pisgah on the east' — the Arabah (the Jordan valley) forms the western edge of the Transjordanian allocation. Chinnereth (the Sea of Galilee) in the north and the Salt Sea (Dead Sea) in the south define the longitudinal extent. The Pisgah slopes mark the eastern edge. The boundary description is precise enough to be verified archaeologically and matches the natural geographic features of the Jordan valley system.</p>",
    "18": "<p>'All your fighting men shall cross over armed before your fellow Israelites' — the military obligation of the Transjordanian tribes to accompany the west-Jordan campaign was a formal covenant stipulation negotiated in Numbers 32. The phrase 'before your fellow Israelites' frames this not merely as military assistance but as the fulfillment of tribal solidarity within the covenant community. In ANE treaty law, vassals who received territory were obligated to render military service to the suzerain's ongoing campaigns; here YHWH's covenant functions as the suzerainty structure requiring cross-tribal military support.</p>",
    "19": "<p>'But your wives, your little ones, and your livestock shall remain in the cities I have given you' — the distinction between combat-ready men who must cross and non-combatants who remain follows ANE military convention. The parenthetical 'I know you have much livestock' acknowledges the very reason Reuben and Gad had requested Transjordanian land (Num 32:1: much livestock). Moses cites the fact as recognition of their legitimate material interest in the land granted, not as criticism of their priorities. Leaving non-combatants also maintained claims to the newly won territory.</p>",
    "20": "<p>'Until the LORD gives rest to your fellow Israelites as he has given rest to you' — the concept of <em>mĕnûḥâ</em> (rest, security) as the goal of the Canaan campaign is a key Deuteronomistic theological term. 'Rest' in this framework is not merely cessation of warfare but the establishment of settled, secure covenant life in the promised land — the completion of YHWH's program. The phrase 'as he has given rest to you' frames the Transjordanian allocation as already-realized rest, setting a precedent and creating obligation: those who have received must support those who have not yet received.</p>",
    "21": "<p>'Your eyes have seen everything the LORD your God has done to these two kings' — the appeal to eyewitness experience of the Sihon and Og campaigns is Joshua's commissioning rationale. Joshua's authority is grounded not in abstract appointment but in observed divine action: he has personally witnessed YHWH's pattern of military deliverance. This is a standard ANE commissioning technique: the new leader's authority is established by appeal to the precedents he witnessed under the previous leader. The Sihon-Og victories become the juridical basis for the promise 'the LORD will do the same to all the kingdoms you are about to enter.'</p>",
    "22": "<p>'Do not fear them, for the LORD your God himself fights for you' — the prohibition of fear (<em>lōʾ tîrāʾûm</em>) is the central psychological and theological requirement of Deuteronomic holy warfare. The phrase 'YHWH your God himself fights for you' (<em>Yhwh ʾĕlōhêkem hû hannilḥām lākem</em>) grounds courage in YHWH's direct military agency rather than Israel's numerical or technological superiority — a claim that runs throughout Deuteronomy (1:30; 20:4) and structures the subsequent conquest theology of Joshua.</p>",
    "23": "<p>'And I pleaded with the LORD at that time' — Moses's intercession (<em>wāʾetḥannan</em>, from <em>ḥānan</em>, to seek favor, implore) is the verb of earnest petition used when the petitioner has no claim of right but only YHWH's mercy to appeal to. This is distinct from prayer grounded in covenant obligation; Moses frames his request as pure plea. The Second Temple tradition developed this moment extensively — Moses's prayer for entry into the land became one of the paradigmatic examples of rejected prayer in rabbinic literature (b. Sotah 13b), used to discuss why even the greatest intercessor's prayer can be refused.</p>",
    "24": "<p>'O Lord GOD, you have only begun to show your servant your greatness and your mighty hand. What god is there in heaven or on earth who can perform deeds and mighty acts like yours?' — the incomparability formula ('what god is there ... who can perform deeds like yours') is one of the most common theological declarations in the Psalms and the Prophets (Ps 35:10; 71:19; Isa 40:18, 25; Mic 7:18). In the ANE polytheistic context, such declarations did not deny the existence of other divine beings but asserted YHWH's supremacy over them. Moses's prayer grounds the request in YHWH's demonstrated power — the Sihon and Og campaigns as evidence of incomparability.</p>",
    "25": "<p>'Please let me cross over and see the good land beyond the Jordan — that good hill country and Lebanon' — the threefold description of the promised land ('good land', 'good hill country', 'Lebanon') clusters the land's desirability in terms of its fertility and elevation. The hill country refers to the central Judean and Ephraimite highlands; Lebanon's mountains would be visible from the northern portions of the land. The emotional weight of the request — Moses's lifelong goal is to see what he worked forty years to deliver Israel toward — makes its denial all the more significant as a theological statement about divine judgment.</p>",
    "26": "<p>Moses's exclusion from Canaan (3:23-27) is narrated as YHWH's refusal of his intercession: 'the LORD was angry with me on your account and would not listen to me.' The precise sin for which Moses is excluded is debated: Numbers 20:12 attributes it to his failure to 'believe in me' and 'uphold me as holy' at Meribah; Numbers 27:14 uses the same formula. In Deuteronomy the narrative reframes the exclusion through Moses's intercession and YHWH's flat refusal — 'Enough from you; do not speak to me of this matter again.' The Hebrew <em>rav-lach</em> (enough for you / it is too much for you) carries both sufficiency and rebuke. Moses is permitted to see the land from Pisgah but not enter — a distinction between visual possession and physical inheritance.</p>",
    "27": "<p>'Go up to the top of Pisgah and look westward, northward, southward, and eastward. Look at it carefully with your eyes, for you shall not cross this Jordan' — Pisgah is the headland of the Abarim range in Moab, northeast of the Dead Sea. The four-directional panoramic vision granted to Moses is a symbolic land-grant: ANE land-grant documents sometimes granted land by symbolic sight as a legal act (cf. Gen 13:14-15: 'lift up your eyes and look ... all the land that you see I will give to you'). Moses receives ownership by vision even without physical entry — the land is his to bequeath to Israel, though not his to inhabit.</p>",
    "28": "<p>'Commission Joshua, and encourage him and strengthen him, for he shall cross over at the head of this people and shall lead them to inherit the land you will see' — the commissioning formula ('encourage him and strengthen him', <em>ḥazzeq wĕʾammeṣ ʾōtô</em>) is the formal language of leadership transfer in the ancient world (Josh 1:6, 7, 9, 18 repeat the formula). Moses's personal relationship with Joshua — mentored since the Amalekite battle (Exod 17:9) and aide at the tent of meeting (Exod 33:11) — means the commission carries personal trust alongside formal authority.</p>",
    "29": "<p>'So we remained in the valley opposite Beth-peor' — Beth-peor ('house of Peor', the Moabite deity) is the location of Israel's encampment before the Jordan crossing and the venue for Moses's farewell addresses. The site opposite Beth-peor (identified near modern Khirbet Ayun Musa) is associated with the Baal-Peor apostasy (Num 25) that Moses refers to at 4:3. Situating Moses's covenant renewal speeches at the very place of Israel's most recent catastrophic failure makes the exhortations of chapters 4-30 all the more urgent — the geography is a standing reminder of the danger being warned against.</p>"
  },
  "4": {
    "1": "<p>'And now, O Israel, listen to the statutes and rules I am teaching you to follow, so that you may live and go in and take possession of the land' — the <em>wĕʿattāh</em> ('and now') formula is the suzerainty-treaty transition from historical prologue (chs. 1-3) to stipulations (chs. 4-26). In Hittite treaties the historical prologue established the basis for obligation; the 'and now' pivot introduced the specific covenant demands. Moses's transition signals that the review of YHWH's acts was not merely historical reminiscence but the motivational foundation for the laws that follow. 'So that you may live' introduces the life-or-death consequence structure that pervades Deuteronomy's covenant theology.</p>",
    "2": "<p>'You shall not add to the word that I command you, nor take from it' — the prohibition on addition and subtraction is the standard ANE canon-formula for authoritative legal texts. Hittite treaties, Mesopotamian law codes, and Egyptian royal inscriptions all contain similar prohibitions against alteration. The same formula appears in Hammurabi's epilogue and in Revelation 22:18-19 at the other end of the biblical canon. The formula functions to close the authoritative corpus: addition would authorize additional obligations; reduction would remove binding requirements. Both distort the suzerain's authentic demands.</p>",
    "3": "<p>'Your eyes have seen what the LORD did at Baal-peor — the LORD your God destroyed from among you every man who followed the Baal of Peor' — the Baal-Peor incident (Num 25:1-9) involved Israelite men engaging in sexual immorality with Moabite women and worshiping a Moabite fertility deity associated with the Peor mountain. Twenty-four thousand Israelites died in the subsequent plague. The incident is cited here as the most recent case study in covenant infidelity with immediate fatal consequences — the audience's generation witnessed it. The appeal to living memory ('your eyes have seen') is the rhetorical foundation of the warning.</p>",
    "4": "<p>'But you who held fast to the LORD your God are all alive today' — the survivors are identified by their covenant loyalty (<em>haddĕbēqîm baYhwh ʾĕlōhêkem</em>, those who clung to YHWH). The verb <em>dābaqa</em> (to cling, cleave) is the same used for marriage union in Gen 2:24 and describes the covenant-loyalty bonding that the Shema demands (Deut 10:20; 11:22; 13:4). Survival at Baal-Peor was not random: those who remained in covenant relation with YHWH survived; those who defected died. The verse presents covenant loyalty as the literal difference between life and death.</p>",
    "5": "<p>'I have taught you statutes and rules, as the LORD my God commanded me, so that you should do them in the land you are entering to possess' — the legislation of Deuteronomy is explicitly contextualized for the land: 'in the land you are entering to possess.' This land-Law link means that exile is not merely geographic displacement but the destruction of the social and legal conditions under which the covenant can be lived. The Mosaic statutes were designed for a specific covenant community in a specific territory — their full observance required the land, making the Exile the covenant's self-destructive consequence for land-violation (Deut 28).</p>",
    "6": "<p>'Keep and carry out these statutes, for this will be your wisdom and understanding before the other peoples, who will hear all these statutes and say, &quot;Surely this great nation is a wise and understanding people&quot;' — the apologetic for Torah wisdom before the nations is remarkable: Israel's covenant law is presented as a public testimony to YHWH's character visible to the surrounding world. In the ANE context, wise law-giving was a mark of divine favor for a nation's king (Hammurabi's prologue claims Marduk's commission to 'bring forth justice in the land'). Israel's statutes are presented as surpassing the wisdom of any ANE law code because they originate with YHWH, not a human king.</p>",
    "7": "<p>'What great nation has a god as close to it as the LORD our God is to us whenever we call upon him?' — YHWH's accessibility through prayer ('whenever we call upon him') is contrasted with ANE deities whose attention required elaborate cultic manipulation and whose responses were uncertain. In Mesopotamian religion, divine accessibility was mediated through complex omens, divination, and temple rituals whose outcome was never guaranteed. Israel's prayer theology — direct address, individual or communal, at any time — represented a structurally different relationship between deity and people: not appeasement of a distant power but communication with a near and responsive suzerain.</p>",
    "8": "<p>'What great nation has statutes and rules as righteous as this entire law I am setting before you today?' — the comparative claim ('as righteous as') invites implicit comparison with the great ANE law corpora: Ur-Nammu (ca. 2100 BCE), Lipit-Ishtar (ca. 1900 BCE), Hammurabi (ca. 1750 BCE), Hittite laws, and Assyrian laws. These codes share surface similarities with Mosaic law (case-law format, lex talionis principles) but differ fundamentally in theological grounding: ANE codes are royal decrees serving the king's political legitimacy; the Mosaic Torah is YHWH's direct covenant with the entire people, making every Israelite — including the king — equally subject to the divine standard.</p>",
    "9": "<p>'Be careful, and guard yourselves diligently, lest you forget the things your eyes have seen, and lest they pass from your heart all the days of your life. Teach them to your children and your children's children' — the memory-transmission obligation is one of Deuteronomy's primary pedagogical structures. The threat is not external attack but internal forgetting (<em>šākaḥ</em>). The antidote is deliberate cross-generational teaching. The Second Temple development of formal Torah education in synagogue contexts, the institution of bar mitzvah as covenant-entry, and the Passover Haggadah's structured retelling of the Exodus all represent institutionalized responses to this verse's teaching mandate.</p>",
    "10": "<p>'Tell them about the day you stood before the LORD your God at Horeb' — the Horeb theophany (the Sinai event in Deuteronomy's terminology) is the foundational revelatory event that all subsequent generations must encounter through transmitted memory. The rabbinic tradition that 'all Israel stood at Sinai' — including future generations — derives from this kind of language: the Horeb experience was paradigmatic and representationally inclusive. Philo of Alexandria developed the Horeb theophany as a model of divine self-disclosure. The Christian parallel is the Eucharist and baptism as enacted memory of Christ's death and resurrection that makes past events present for each generation.</p>",
    "11": "<p>'The mountain burned with fire up to the heart of heaven, wrapped in darkness, cloud, and deep gloom' — the Sinai theophany's triple atmospheric phenomena (darkness, <em>ʿānān</em> cloud, <em>ʿărāpel</em> deep darkness) combine natural storm imagery with the ANE conventions for divine appearance: gods appeared in storm, cloud, and fire throughout the Near Eastern world. The storm theophany was YHWH's primary mode of manifestation (Ps 18:7-15; 29; 50:3). The paradox of fire and darkness together is deliberate: YHWH is present and self-revealing, yet transcendent and unseen — the theological logic for the aniconic requirement that follows in 4:15-18.</p>",
    "12": "<p>The Horeb prohibition of images is grounded in the nature of the Sinai theophany itself: 'you heard the sound of words but saw no form (<em>temunah</em>); there was only a voice' (4:12). Israel's aniconic tradition is historically distinctive — ancient Near Eastern religion was uniformly iconic: divine images (<em>ṣalmu</em> in Akkadian) were the physical locus of the deity's presence, 'activated' through mouth-washing and mouth-opening rituals. To worship without an image was anomalous. Greco-Roman observers noted it with derision: Tacitus writes that Jews 'acknowledge one God only ... of unbounded might, and eternal, neither admitting of any representative in human shape.' Deuteronomy grounds aniconism not merely in prohibition but in the nature of the Horeb revelation itself: YHWH is the God who speaks without being seen — the word, not the image, is the medium of divine self-communication.</p>",
    "13": "<p>'He declared to you his covenant, which he commanded you to keep — the Ten Commandments — and he wrote them on two tablets of stone' — the Decalogue's designation as the <em>bĕrît</em> (covenant) rather than merely 'the law' is theologically significant: the Ten Commandments are the covenant document itself. The two stone tablets are the treaty-copy standard: ANE suzerainty treaties were always written in duplicate, one copy for each party. The tablets placed 'in the ark' (10:2, 5) follow treaty-archive custom: the treaty copy was stored at the god's temple. The tablets in the ark are Israel's treaty copy deposited before YHWH — a living legal document, not merely a religious display.</p>",
    "14": "<p>'And the LORD commanded me at that time to teach you statutes and rules for you to carry out in the land you are crossing over to possess' — Moses's mediatorial role is explicit: YHWH spoke the Decalogue to the people (4:12-13), but commissioned Moses to teach the statutes and rules. This bifurcation — direct divine speech for the Decalogue, Mosaic mediation for the detailed legislation — reflects the narrative structure of Exodus 20-24 (Decalogue directly, Book of the Covenant through Moses). The Deuteronomistic tradition understands Moses as the covenant-interpreter par excellence, whose role the later prophets continued.</p>",
    "15": "<p>'Therefore watch yourselves very carefully. Since you saw no form on the day the LORD spoke to you at Horeb out of the midst of the fire' — the conclusion drawn from Horeb's formless voice is the entire weight of the Second Commandment's reasoning. The logic is: since YHWH appeared without form, any image-making is a human invention imposed on divine self-disclosure, not a legitimate aid to worship. The Reformation tradition (Calvin, Institutes 1.11-12) built its anti-image theology directly on this verse's argument. The Deuteronomic logic also implies that idolatry is epistemologically dishonest: it misrepresents YHWH's own chosen mode of self-revelation.</p>",
    "16": "<p>'Do not act corruptly by making for yourselves a carved image in the form of any figure — the likeness of male or female' — the prohibited image categories begin with anthropomorphic forms. The specific prohibition on human-form images contrasts with Egypt's ubiquitous anthropomorphic deity representations and the Canaanite male/female deity pairs. Asherah poles (female goddess symbol) and bull images (male deity power symbol) are the specific temptations Israel faced in Canaan. The verb 'act corruptly' (<em>šāḥat</em>) frames image-making not as innocent religious art but as covenant-violation that corrupts the worshiper's fundamental relationship with YHWH.</p>",
    "17": "<p>'The likeness of any animal on the earth, the likeness of any winged bird that flies in the sky' — terrestrial and avian animal images are the second and third prohibited categories. Egypt's theology systematically depicted deities as animal hybrids: Ra as sun-disk or hawk, Anubis as jackal, Hathor as cow, Horus as falcon. The prohibition on animal images is a direct counter to Egyptian iconographic theology. The enumeration (human, animal, bird, fish) roughly follows the creation order of Genesis 1:20-27 — YHWH's creatures are not YHWH's representations; the creation cannot be an icon of the creator.</p>",
    "18": "<p>'The likeness of anything that creeps on the ground, the likeness of any fish in the water beneath the earth' — the prohibition extends to creeping things and fish, completing the Genesis 1 creation categories. Serpent imagery was pervasive in Egyptian religious iconography (the uraeus cobra on pharaoh's crown, the Nehebkau serpent deity). Fish deities were prominent in the Philistine Dagon cult and Mesopotamian Oannes traditions. The comprehensive list forecloses any route of naturalistic image-making as legitimate worship: nothing in the created order may serve as YHWH's icon because YHWH disclosed himself as voice, not form.</p>",
    "19": "<p>'Beware lest you lift your eyes to heaven and see the sun and moon and stars — the whole host of heaven — and be drawn away to bow down and serve them, things the LORD your God has allotted to all the peoples under the whole heaven' — the astral religion warning addresses the Mesopotamian star-worship that was the dominant religious technology of the ancient Near East. Babylonian astrology, the worship of Sin (moon), Shamash (sun), Ishtar (Venus), and the star-gods was the prestige religion of the imperial cultures. The remarkable statement 'the LORD has allotted to all the peoples under the whole heaven' (i.e., permitted the nations to worship astral bodies) distinguishes Israel's exclusive covenant with YHWH from the religious arrangements of other nations.</p>",
    "20": "<p>'But the LORD has taken you and brought you out of the iron furnace, out of Egypt, to be a people belonging to his own inheritance, as you are today' — the 'iron furnace' (<em>kûr habbarzel</em>) is a metallurgical metaphor for Egypt's intensely purifying oppression: iron smelting required extreme heat and pressure. The same image appears in Jer 11:4 and 1 Kings 8:51. Egypt was not merely slavery but the crucible in which Israel as a covenant people was formed. The metaphor also invokes YHWH's incomparability: no other god attempted to take one nation out of another by such means (cf. 4:34). Israel's national identity was forged by the Exodus and belongs to YHWH as his inheritance.</p>",
    "21": "<p>'Furthermore, the LORD was angry with me on your account and swore that I would not cross the Jordan' — the repetition of Moses's exclusion in the context of the image-prohibition warning is structurally deliberate: Moses's fate functions as the most vivid illustration of covenant seriousness. The exclusion of the covenant mediator himself demonstrates that covenant consequences apply without distinction of rank. YHWH's anger was triggered by the waters-of-Meribah failure (Num 20:10-12), which the Deuteronomic tradition frames as Moses's solidarity with Israel's rebellion — a representational consequence, not a personal one in isolation.</p>",
    "22": "<p>'I must die in this land; I am not to cross the Jordan. But you shall cross over and possess that good land' — the contrast between Moses's death in Moab and Israel's crossing emphasizes the representational logic: Moses the leader dies bearing the representative consequence; the people receive the land. The brevity of the verse — three short clauses — mirrors the finality of the statement. The pattern anticipates Christ's death as the representative who does not enter the earthly possession but whose death enables his people's entry into the eschatological inheritance (Heb 3:5-6: Moses as servant vs. Christ as Son).</p>",
    "23": "<p>'Be careful not to forget the covenant of the LORD your God that he made with you, and make a carved image in the form of anything the LORD your God has forbidden you' — the covenant-memory command positions image-making specifically as covenant forgetting: to make an image is to forget the Horeb theophany's formless voice-revelation. The covenant is not a set of abstract obligations but a specific historical relationship (YHWH who spoke from Horeb, who brought you from Egypt) — forgetting that history is the cognitive condition that makes idolatry seem reasonable and permissible.</p>",
    "24": "<p>'For the LORD your God is a consuming fire, a jealous God' — the consuming fire metaphor (<em>ʾēš ʾōkĕlāh</em>) connects the Horeb fire-theophany (4:11-12) to YHWH's jealous exclusivity. In ANE contexts, divine jealousy (<em>qannāʾ</em>) is not a psychological flaw but the theological claim of exclusive relationship: YHWH alone is Israel's God, and Israel's exclusive loyalty is the covenant's foundational requirement. The same language appears in the Decalogue's Second Commandment context (Exod 20:5). The Hebrews writer cites this verse (Heb 12:29) in the context of the new covenant's Zion-theophany, demonstrating the enduring force of the consuming-fire characterization.</p>",
    "25": "<p>'When you have children and grandchildren and have grown old in the land, and if you act corruptly by making a carved image' — the conditional clause ('when you have grown old in the land') anticipates the pattern of prosperous complacency leading to covenant violation — a theme the Deuteronomistic History traces through every Israelite king after Solomon. Prosperity and length of tenure in the land breed the memory-failure that produces idolatry. The warning is addressed specifically to the generation-after-generation future, not merely the immediate audience, because the danger grows with time rather than diminishing.</p>",
    "26": "<p>'I call heaven and earth as witnesses against you today that you will quickly perish from the land' — calling heaven and earth as covenant witnesses is an ANE treaty convention attested in Hittite suzerainty treaties (which invoked gods, mountains, rivers, heaven, and earth as witnesses). Since no other deity above YHWH could serve as covenant witness for Israel, heaven and earth function as impersonal cosmic witnesses. The same invocation appears in Deut 30:19; 31:28; 32:1 (Moses's song calls heaven and earth to hear). The witness invocation makes covenant violation a publicly attested breach before the whole cosmic order.</p>",
    "27": "<p>'The LORD will scatter you among the peoples, and you will be left few in number among the nations where the LORD will drive you' — the exile prophecy of Deut 4:27-28 is one of the earliest and most explicit in the Deuteronomic tradition. The scattering language (<em>hēpîṣ</em>, to scatter/disperse) is the technical term for diaspora throughout the Deuteronomistic History and the prophets (Jer 9:16; Ezek 12:15; 20:23). The prophecy's fulfillment in the Assyrian deportation of the northern kingdom (722 BCE) and the Babylonian deportations (605, 597, 586 BCE) gave Deuteronomy 4's warnings retrospective force as covenant documentation of what the exile meant.</p>",
    "28": "<p>'And there you will serve gods made by human hands — wood and stone — that can neither see, nor hear, nor eat, nor smell' — the idol polemic ('cannot see, hear, eat, smell') is the standard Israelite critique of images, developed extensively in Isa 40:18-20; 44:9-20; Ps 115:4-8; 135:15-18. The irony is pointed: Israel will be forced to live in proximity to the impotent idols their own covenant-breaking pushed them toward. The four verbs (see, hear, eat, smell) invert four sensory activities YHWH performs in relation to Israel: he sees their affliction, hears their cry, provides food, accepts their offerings. Dead idols are the anti-YHWH.</p>",
    "29": "<p>'But from there you will seek the LORD your God and you will find him, if you search for him with all your heart and with all your soul' — the restoration promise in the midst of the exile warning is one of Deuteronomy's theological pillars. The two key verbs — <em>bāqaš</em> (to seek) and <em>māṣāʾ</em> (to find) — describe diligent pursuit that results in genuine encounter. The condition 'with all your heart and with all your soul' employs the Shema's vocabulary (6:5) applied to the exile-seeker: the total-person devotion demanded in covenant loyalty is also the mode of repentance that leads to restoration.</p>",
    "30": "<p>'When you are in distress and all these things have come upon you, in the latter days you will return to the LORD your God and listen to his voice' — the phrase 'in the latter days' (<em>bĕʾaḥărît hayyāmîm</em>) is eschatological language marking a future decisive moment. In context it refers to the post-exilic restoration, but the phrase carries forward-pointing force throughout the Prophets (Isa 2:2; Jer 23:20; Ezek 38:16; Dan 10:14). Paul reads Deuteronomy's exile-and-return cycle as the prototype for the eschatological gathering of all Israel (Rom 11:25-27). The cycle of rebellion-exile-return is the structural spine of the Deuteronomistic History.</p>",
    "31": "<p>'For the LORD your God is a merciful God. He will not abandon you or destroy you or forget the covenant with your fathers that he swore to them' — <em>raḥûm</em> (merciful, compassionate) is the tender maternal-care term derived from <em>reḥem</em> (womb). The three divine commitments — not abandon, not destroy, not forget the covenant — are the positive counterpart to Israel's failures. The patriarchal covenant (sworn to the fathers) is the theological bedrock beneath Israel's repeated failures: the Abrahamic covenant is the unconditional grant upon which the conditioned Mosaic covenant rests. When Israel's Mosaic obligation fails, YHWH's Abrahamic commitment endures.</p>",
    "32": "<p>'For ask now about the former days that were before you, since the day God created mankind on the earth, and search from one end of heaven to the other: has any such great thing as this ever happened?' — Moses challenges his audience to test YHWH's incomparability by universal historical survey. The rhetorical scope ('from the day God created mankind ... from one end of heaven to the other') frames the following questions about the Exodus and Sinai revelation as uniquely unprecedented in all of human history — not merely impressive in Israel's experience but without parallel in universal human experience. This is the most comprehensive apologetic claim in Deuteronomy.</p>",
    "33": "<p>'Did any people ever hear the voice of God speaking out of the midst of fire, as you have heard, and survive?' — the claim that Israel survived the Horeb fire-theophany reflects both the ANE convention of divine fire as mortal danger and the specific Horeb miracle. Mesopotamian and Egyptian texts associate divine fire-theophanies with death-consuming holiness. Israel's survival of direct divine address from fire was understood as a unique miracle — YHWH's accommodation of his transcendent holiness to the capacity of human hearing. The Psalmist and the Prophets reflect on Horeb's fire as the archetype of covenant encounter (Ps 29; Hab 3).</p>",
    "34": "<p>'Or has any god ever attempted to go and take one nation out of the midst of another nation — by tests, by signs and wonders, by war, by a mighty hand and an outstretched arm, and by great terrors — like all that the LORD your God did for you in Egypt before your eyes?' — the five-fold description of the Exodus mechanisms (tests, signs and wonders, war, mighty hand, outstretched arm, great terrors) is one of the most comprehensive catalogs of divine saving action in the OT and becomes the formula for reciting the Exodus throughout Deuteronomy and the Psalms. The six-element formula in varying combinations appears in Deut 6:21-22; 7:8; 9:26; 26:8; Ps 136:12; Jer 32:21 — it became the liturgical template for remembering YHWH's saving work.</p>",
    "35": "<p>'To you it was shown so that you would know that the LORD is God; there is no other besides him (<em>ʾên ʿôd</em>)' — <em>ʾên ʿôd</em> ('there is no other') is the most absolute monotheistic formula in the OT and becomes the signature affirmation of Second Isaiah (Isa 45:5, 6, 14, 18, 21, 22; 46:9). The phrase functions here as the conclusion of the historical-theological argument: the Exodus and Horeb events were pedagogical demonstrations designed to teach Israel the uniqueness of YHWH. The knowledge is not philosophical deduction but revelatory demonstration: 'to you it was shown so that you would know' — divine display serves an epistemological purpose in covenant education.</p>",
    "36": "<p>'Out of heaven he let you hear his voice to discipline you, and on earth he showed you his great fire, and you heard his words out of the midst of the fire' — the spatial distinction between heavenly voice and earthly fire describes YHWH's transcendence-in-presence: the voice originates in heaven (YHWH is not localized to the mountain) while the fire phenomenon is earthly and observable. The verb <em>yissar</em> (to discipline, instruct) reveals the purpose of theophany: not terror for its own sake but formation of the covenant people's knowledge and obedience. The heavenly origin of the divine voice distinguishes YHWH from chthonic or mountain deities of the ANE.</p>",
    "37": "<p>'And because he loved your fathers and chose their descendants after them, he brought you out of Egypt himself, with his great power' — the theology of election is grounded in prior covenantal love (<em>ʾāhab</em>) for the patriarchs. The word 'chose' (<em>bāḥar</em>) is the technical Deuteronomic election term: YHWH's selection of Israel is not based on Israel's merit (7:7-8: 'it was not because you were more in number ... it is because YHWH loves you and keeps the oath that he swore to your fathers'). The phrase 'himself, with his great power' emphasizes YHWH's personal agency in the Exodus — not through an intermediary but directly.</p>",
    "38": "<p>'To drive out before you nations greater and mightier than you, to bring you in and give you their land as an inheritance, as it is today' — the dispossession of larger nations is the practical evidence of YHWH's committed power on Israel's behalf. The phrase 'as it is today' is the Deuteronomic historian's formula for events already completed from the writing perspective — the same formula used at 2:22; 3:14; 4:20, 38. It signals that the text is written after the conquest, using historical fulfillment as a pedagogical tool: what Moses predicted, YHWH delivered, validating Moses's warnings and promises for the future.</p>",
    "39": "<p>'Know therefore today, and take it to heart, that the LORD is God in heaven above and on the earth beneath — there is no other' — the repeated <em>ʾên ʿôd</em> formula (first at 4:35, now at 4:39) functions as the chapter's theological inclusio and its climactic affirmation. The addition of 'in heaven above and on the earth beneath' expands the claim from uniqueness to cosmic sovereignty: no domain exists — neither the celestial realm where ANE astral deities operated nor the earthly realm where territorial gods held sway — in which YHWH is not the sole God. This verse is the theological summit of Deuteronomy 4's extended apologetic argument.</p>",
    "40": "<p>'Therefore keep his statutes and commandments that I am giving you today, so that it may go well with you and with your children after you, and so that you may live long in the land that the LORD your God is giving you for all time' — the concluding exhortation connects the theological argument (YHWH is uniquely God) to its practical consequence (covenant obedience). The incentive formula ('so that it may go well ... and so that you may live long') is Deuteronomy's standard motivation structure: covenant obedience produces flourishing; covenant violation produces destruction. 'For all time' (<em>kol-hayyāmîm</em>) frames the land-tenure as YHWH's perpetual gift, contingent only on sustained covenant loyalty.</p>",
    "41": "<p>Moses sets apart three cities of refuge east of the Jordan 'so that a manslayer could flee there.' The cities-of-refuge institution is developed in Num 35:6-34 and Deut 19:1-13. The three Transjordanian cities are established here even before the western Jordan cities are possible — Moses can only designate what lies within Israel's current holdings. The institution reflects the ANE principle of asylum: temples and designated sites provided refuge from blood-avengers. The Mosaic adaptation channels the asylum principle into a legal institution requiring adjudication of intent (premeditated vs. accidental homicide) before the manslayer's status is determined.</p>",
    "42": "<p>'Anyone who kills his neighbor unintentionally without prior enmity — and by fleeing to one of these cities could live' — the distinguishing criterion for the cities of refuge is intent: 'without prior enmity' (<em>bĕlî-daʿat</em>, without knowledge/intent) identifies the unpremeditated killing. The avenger-of-blood system (<em>gōʾēl haddām</em>) was the pre-institutional mechanism for addressing homicide in tribal societies; the cities of refuge created a legal buffer between killing and automatic retribution, allowing for judicial determination. The protection of the unintentional killer reflects the Mosaic legal principle that punishment must be proportionate to intent.</p>",
    "43": "<p>'Bezer in the wilderness on the tableland for the Reubenites; Ramoth in Gilead for the Gadites; and Golan in Bashan for the Manassites' — the three Transjordanian cities of refuge correspond to the three tribal territories established in Deut 3:12-17: Bezer for Reuben's southern territory (modern site uncertain, probably in the Madeba plateau), Ramoth-Gilead for Gad's central hill country (modern Tell Ramith in northern Jordan), and Golan for Manasseh's northern Bashan territory (modern Sahm el-Jolan). These cities are matched by three western cities in Deut 19 (Josh 20:7: Kedesh, Shechem, Hebron), completing a network of six asylum cities across the entire territory.</p>",
    "44": "<p>'This is the law that Moses set before the people of Israel' — the colophon sentence (<em>wĕzōʾt hattôrāh ʾăšer-śām mōšeh lipnê bĕnê yiśrāʾēl</em>) functions as a formal heading or subscription for what follows. The term <em>tôrāh</em> here refers not to the entire Pentateuch but to the specific covenant instruction that begins in chapter 5 with the Decalogue. The colophon signals a structural transition: chapters 1-3 were historical retrospective; chapter 4 was theological argument for covenant loyalty; chapters 5-26 are the detailed covenant stipulations Moses transmitted.</p>",
    "45": "<p>'These are the testimonies, the statutes, and the rules that Moses spoke to the Israelites after they came out of Egypt' — the three-fold legal vocabulary (<em>ʿēdōt</em>, testimonies/ordinances; <em>ḥuqqîm</em>, statutes; <em>mišpāṭîm</em>, rules/judgments) is Deuteronomy's standard legal taxonomy. Testimonies (<em>ʿēdōt</em>) are covenant-stipulations bearing witness to YHWH's character; statutes (<em>ḥuqqîm</em>) are fixed ordinances, often cultic; rules (<em>mišpāṭîm</em>) are case-law judgments derived from precedent. The subscript 'after they came out of Egypt' situates the entire Deuteronomic law as Exodus-consequence: the redeemed people receive the redeemer's requirements.</p>",
    "46": "<p>'East of the Jordan in the valley opposite Beth-peor, in the land of Sihon king of the Amorites, who lived at Heshbon' — the geographic specificity — Beth-peor, Sihon's land, Heshbon — situates the law within the narrative of conquest: Moses speaks from territory already won. The mention of Beth-peor echoes 3:29 and anticipates 4:3's Baal-peor warning; the juxtaposition of the covenant-renewal location with the site of Baal-Peor apostasy is consistent Deuteronomic irony. 'The land of Sihon' frames the present location as evidence of YHWH's faithfulness in the immediate past, grounding the authority of the law being given.</p>",
    "47": "<p>'They had taken possession of his land and the land of Og king of Bashan — the two Amorite kings east of the Jordan' — the summary identification of the two Transjordanian victories (Sihon and Og) as the territorial basis for Moses's teaching location recapitulates chapters 2-3. The phrase 'the two Amorite kings east of the Jordan' becomes a standard Deuteronomistic shorthand for the first-fruits of the conquest (Josh 2:10; 9:10; 1 Kings 4:19). The concluding geographic summary frames the entire body of Moses's addresses as given from the firstfruits of YHWH's promised land.</p>",
    "48": "<p>'From Aroer on the rim of the Valley of the Arnon as far as Mount Sirion — that is, Hermon' — the south-to-north geographic bracket (Aroer on the Arnon in the south, Hermon in the north) reprises the territorial summary of 3:8. Mount Sirion as the Sidonian name for Hermon was already noted in 3:9. The repetition of the geographic bracket in the colophon (vv. 44-49) creates a formal envelope: the law's setting is precisely defined. The Aroer-to-Hermon range describes the full extent of Transjordanian territory over which Moses spoke — won from Sihon and Og, distributed to Reuben, Gad, and Manasseh.</p>",
    "49": "<p>'Along with all the Arabah east of the Jordan as far as the Sea of the Arabah, under the slopes of Pisgah' — the colophon's final geographic marker, the Arabah and Pisgah, closes the retrospective precisely where chapter 3 ended: Moses's Pisgah vision (3:27) and the encampment at Beth-peor (3:29). The geographic frame of the entire Transjordanian section (chs. 1-4) is thus Pisgah: the mountain from which Moses viewed what he could not enter. The concluding mention of the Sea of the Arabah and Pisgah completes the boundary description of Reuben, Gad, and Manasseh's territory and marks the formal close of the historical-theological prologue before the Decalogue begins in chapter 5.</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'deuteronomy')
    merge_comm(existing, DEUTERONOMY)
    save_comm('mkt-context', 'deuteronomy', existing)
    print('Deuteronomy 3–4 mkt-context written.')

if __name__ == '__main__':
    main()
